    "vorm": "** <b>ἄγκυρα</b>, <span class=\"greek\">-ας, ἡ</span> (< <span class=\"greek\">ἄγκος</span>, <i>a bend</i>), [in Sm.: Je 52:18*;]",
    "definitie": "<em>an anchor</em>: Ac 27:29, 30 40; fig. (MM, <i>VGT</i>, s.v.), He 6:19.†",
