  "G80": {
    "woord": "ἀδελφός",
    "gloss": "a brother",
    "vorm": "<b>ἀδελφός</b>, <span class=\"greek\">-οῦ, ὁ</span>",
    "definitie": "in cl., <em>a brother</em>, born of the same parent or parents. [In LXX (Hort, <i>Ja.</i>, 102 f.), for <span class=\"hebrew\">אָח</span>;] <br/>1. lit. of a brother (Ge 4:2, al.). <br/>2. Of a neighbour (Le 19:17). <br/>3. Of a member of the same nation (Ex 2:14, De 15:3). In NT in each of these senses (1. Mt 1:2, al.; 2. Mt 7:3; 3. Ro 9:3) and also, <br/>4. of a fellow-Christian: I Co 1:1, Ac 9:30. This usage finds illustration in <span class=\"greek\">π.</span>, where <span class=\"greek\">ἀ.</span> is used of members of a pagan religious community (M, <i>Th.</i>, I, 1:4; MM, <i>VGT</i>, s.v.). The <span class=\"greek\">ἀδελφοὶ τ. Κυρίου</span> (Mt 12:46-49 13:55 28:10, Mk 3:31-34, Lk 8:19-21, Jo 2:12 7:3, 5 10 20:17, Ac 1:14, I Co 9:5) may have been sons of Joseph and Mary (Mayor, <i>Ja.</i>, Intr. viff.; <i>DB</i>, i, 320 ff.) or of Joseph by a former marriage (Lft., <i>Gal.</i>, 252ff.; <i>DCG</i>, i, 232 ff.), but the view of Jerome, which makes <span class=\"greek\">ἀ.</span> equivalent to <span class=\"greek\">ἀνεψιός</span>, is inconsistent with Greek usage. (Cremer, 66.)",
    "nt": "343",
    "etymologie": "(< <span class=\"greek\">ἀ-</span> copul., <span class=\"greek\">δελφύς</span>, <i>womb</i>),"
  },
  "G81": {
    "woord": "ἀδελφότης",
    "gloss": "brotherhood, brotherly affection",
    "vorm": "**† <b>ἀδελφότης</b>, <span class=\"greek\">-ητος, ἡ</span>",
    "definitie": "<br/>1. abstract, <em>brotherhood, brotherly affection</em> (LXX). <br/>2. Concrete, <em>the brotherhood</em>, the Christian community: I Pe 2:17 5:9 (MM, <i>VGT</i>, s.v.).†",
    "nt": "2",
    "etymologie": "(< <span class=\"greek\">ἀδελφός</span>), [in LXX: I Mac 12:10, 17, IV Mac5*;]"
  },
