    "definitie": "<em>injustice</em>: Lk 18:6, Ro 9:14.",
    "nt": "25",
    "etymologie": "(< <span class=\"greek\">ἄδικος</span>), [in LXX for <span class=\"hebrew\">עָוֹן</span>, <span class=\"hebrew\">פֶּשַׁע</span>, <span class=\"hebrew\">עָוֶל</span>, etc.;]"
