    "nt": "1",
    "etymologie": "(< <span class=\"greek\">αἰνέω</span>), [in LXX chiefly for <span class=\"hebrew\">תּוֹדָה</span>, <span class=\"hebrew\">תְּהִלָּה</span>;]"
