  "G138": {
    "woord": "αἱρέω",
    "gloss": "to take",
    "vorm": "<b>αἱρέω</b>,",
    "definitie": "<em>to take</em>; Mid., <span class=\"greek\">-ομαι</span> (M, <i>Pr</i>., 158 f.; MM, <i>VGT</i>, s.v.), <em>to choose</em>: Phl 1:22, II Th 2:13, He 11:25. (Cf. <span class=\"greek\">ἀν-</span>, <span class=\"greek\">ἀφ-</span>, <span class=\"greek\">δι-</span>, <span class=\"greek\">ἐξ-</span>, <span class=\"greek\">καθ-</span>, <span class=\"greek\">περι-</span>, <span class=\"greek\">προ-αιρέω</span>.)†",
    "nt": "3",
    "etymologie": "[in LXX for <span class=\"hebrew\">אמר</span> hi., <span class=\"hebrew\">בּחר</span>, etc.;]"
  },
