  "G315": {
    "woord": "ἀναγκάζω",
    "gloss": "to necessitate",
    "vorm": "<b>ἀναγκάζω</b>",
    "definitie": "<em>to necessitate</em>, <em>compel by force</em> or<em> persuasion, constrain</em>: c. acc., II Co 12:11; id. c. inf., Mt 14:22, Mk 6:45, Lk 14:23, Ac 26:11 (on the impf. here, v. Field, <i>Notes</i>, 141; M, <i>Pr.</i>, 128 f., 247), Ga 2:14 6:12; pass., C. inf., Ac 28:19, Ga 2:3 (for exx., v. MM, <i>VGT</i>, s.v.).†",
    "nt": "9",
    "etymologie": "(< <span class=\"greek\">ἀνάγκη</span>), [in LXX: Pr 6:7 (<span class=\"hebrew\">שֹׁטֵר</span>), I Es 3:24, I Mac 2:25, al.;]"
  },
