    "gloss": "necessary",
    "vorm": "** <b>ἀναγκαῖος</b>, <span class=\"greek\">-αῖα, -αῖον</span>",
    "definitie": "<em>necessary</em>: Ac 13:46, I Co 12:22, II Co 9:5, Phl 2:25, Tit 3:14, He 8:3; comp. <span class=\"greek\">-αιότερον</span>, Phl 1:24.",
    "nt": "8",
