    "etymologie": "(<span class=\"greek\">ἀνά</span>, <span class=\"greek\">ἵημι</span>), [in LXX for <span class=\"hebrew\">רפה</span>, <span class=\"hebrew\">נשׂא</span>, etc.;]"
