    "nt": "6",
    "etymologie": "(<span class=\"greek\">ἀ-</span> neg., <span class=\"greek\">νοητός</span>; < <span class=\"greek\">νοέω</span>), [in LXX: Pr 17:28 (<span class=\"hebrew\">אֱוִיל</span>), Si 42:8, al.;]"
