  "G565": {
    "woord": "ἀπ-έρχομαι",
    "gloss": "to go away",
    "vorm": "<b>ἀπ-έρχομαι</b>,",
    "definitie": "<em>to go away</em>, <em>depart</em> (also, in late writers, with \"perfective\" force, <em>to arrive</em> at a destination, the thought being carried on to the goal; M, <i>Pr.</i>, 111 f., 247; MM, s.v.); <br/>(a) absol.: Mt 13:25, al.; ptcp., <span class=\"greek\">ἀπελθών</span>, used pleonastically with other verbs as in Heb. (Dalman, <i>Words</i>, 21), Mt 13:28, al.; <br/>(b) with mention of place or person: <span class=\"greek\">εἰς</span>, Mt 14:15; <span class=\"greek\">ἐπί</span>, Lk 24:24; <span class=\"greek\">πρός</span>, Re 10:9; <span class=\"greek\">ἀπό</span>, Lk 1:38; <span class=\"greek\">ἐξω</span>, Ac 4:15; <span class=\"greek\">ἐκεῖ</span>, Mt 2:22.",
    "nt": "126",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">הלךְ</span>;]"
  },
  "G568": {
    "woord": "ἀπ-έχω",
    "gloss": "to hold back",
    "vorm": "<b>ἀπ-έχω</b>,",
    "definitie": "trans., <br/>(a) <em>to hold back</em>, <em>keep off</em>; <br/>(b) <em>to have in full</em>, <em>to have received</em> (on the \"punctiliar\" force of the compound, v. M, <i>Pr.</i>, 109, 247): c. acc., Mt 6:2, 5, 16, Lk 6:24, Phl 4:18, Phm 15 (for illustr. from <span class=\"greek\">π.</span>, where it is used in receipts, v. Deiss., <i>BS</i>, 229; <i>LAE</i>, 110 f.; MM, s.v.); impers., <span class=\"greek\">ἀπέχει</span> (Field, <i>Notes</i>, 39), <em>it is enough</em>: Mk 14:41.",
    "nt": "25",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">רחק</span>;]"
  },
