    "definitie": "<em>restoration</em>: Ac 3:21 (in <span class=\"greek\">π.</span> of repairs and restorations of temples, v. MM, s.v.).†",
    "nt": "1",
    "etymologie": "(< <span class=\"greek\">ἀποκαθίστημι</span>),"
