    "vorm": "† <b>ἀργυροκόπος</b>, <span class=\"greek\">-ου, ὁ</span>",
    "definitie": "<em>a silversmith</em>: Ac 19:24 (Plut.; <span class=\"greek\">π.</span>, v. MM, s.v.).†",
    "nt": "1",
