  "G746": {
    "woord": "ἀρχή",
    "gloss": "beginning",
    "vorm": "<b>ἀρχή</b>, <span class=\"greek\">-ῆς, ἡ</span>,",
    "definitie": "<em>beginning</em>, <em>origin</em>; <br/>(a) absol., of the beginning of all things: of God as the Eternal, the First Cause, Re 21:6 (cf. 1:8); similarly, of Christ, Re 22:13; of Christ as the uncreated principle, the active cause of creation, Re 3:14; in his relation to the Church, Col 1:18; <span class=\"greek\">ἐν ἀ.</span>, Jo 1:1, 2; <span class=\"greek\">ἀπ᾽ ἀ.</span> (and <span class=\"greek\">ἀπ᾽ ἀ. κτισεως</span>), Mt 19:4, 8 24:21, Mk 10:6 13:19, Jo 8:44, II Th 2:13, II Pe 3:4, I Jo 1:1 2:13, 14 3:8; <span class=\"greek\">κατ’ ἀρχάς</span>, He 1:10; <br/>(b) relatively: He 7:3; <span class=\"greek\">ἀ. ὠδίνων</span>, Mt 24:8, Mk 13:9; <span class=\"greek\">τ. σημείων</span>, Jo 2:11; <span class=\"greek\">τ. ὑποστάσεως</span>, He 3:14; <span class=\"greek\">τ. λογίων</span>, He 5:12; <span class=\"greek\">ὁ τ. ἀρχῆς τ. Χριστοῦ λόγος</span>, the account of the beginning, the elementary view of Christ, He 6:1; <span class=\"greek\">ἀρχὴν λαμβάνειν</span>, to begin, He 2:3; <span class=\"greek\">ἐξ ἀ.</span>, Jo 6:64 16:4; <span class=\"greek\">ἀπ’ ἀ.</span>, Lk 1:2, Jo 15:27, I Jo 2:7, 24 3:11, II Jo 5, 6; <span class=\"greek\">ἐν ἀ.</span>, Ac 11:15 26:4, Phl 4:15; <span class=\"greek\">τὴν ἀρχήν</span>, adverbially, <em>at all</em> (Hdt., al.; v MM, s.v.): Jo 8:25.",
    "nt": "55",
    "etymologie": "[in LXX for <span class=\"hebrew\">קֶדֶם</span>, <span class=\"hebrew\">רֹאשׁ</span>, <span class=\"hebrew\">רֵאשִׁית</span>, etc.;]"
  },
  "G747": {
    "woord": "ἀρχηγός",
    "gloss": "beginning",
    "vorm": "<b>ἀρχηγός</b>, <span class=\"greek\">-όν</span>,",
    "definitie": "<em>beginning</em>, <em>originating</em>: more freq., as subst.; <br/>1. <em>founder</em>, <em>author</em> (Lat. auchor; so sometimes in <span class=\"greek\">π.</span>, v. MM, s.v.; Milligan, <i>NTD</i>, 75): Ac 3:15 (R, mg.), He 2:10 (R, txt.; but v. Westc., in l., and Page, Ac 3:15). <br/>2. <em>prince</em>, <em>leader</em> (so in MGr., v. Kennedy, <i>Sources</i>, 153): Ac 3:15 (R, txt.) 5:31, He 2:10 (cf. R, mg.) 12:2 (Cremer, 117).†",
    "nt": "4",
    "etymologie": "[in LXX for <span class=\"hebrew\">רֹאשׁ</span>, <span class=\"hebrew\">נָשִׂיא</span> etc.;]"
  },
  "G748": {
    "woord": "ἀρχ-ιερατικός",
    "gloss": "high-priestly",
    "vorm": "*† <b>ἀρχ-ιερατικός</b>, <span class=\"greek\">-ή, -όν</span>",
    "definitie": "<em>high-priestly</em>: Ac 4:6 (MM, s.v.).",
    "nt": "1",
    "etymologie": "(< <span class=\"greek\">ἀρχιερύς</span>),"
  },
  "G749": {
    "woord": "ἀρχ-ιερεύς",
    "gloss": "high-priest",
    "vorm": "<b>ἀρχ-ιερεύς</b>, <span class=\"greek\">-έως, ὁ</span>,",
    "definitie": "<br/>1. <em>high-priest</em>: Mk 2:26 14:47, al.; of Christ: He 2:17 3:1, al. <br/>2. In pl., <em>chief priests</em>, including ex-high-priests and members of high-priestly families: Mt 2:4, Mk 8:31, al. (Cremer, 294; <i>DCG</i>, i, 297 f.; MM, s.v.).",
    "nt": "122",
    "etymologie": "[in LXX for <span class=\"hebrew\">כֹּהֵן</span>, <span class=\"hebrew\">הַגָּדוֹל</span> <span class=\"hebrew\">כּ״</span>, <span class=\"hebrew\">הָרֹאשׁ</span> <span class=\"hebrew\">כּ״</span>;]"
  },
