    "etymologie": "(pres. ptcp. of <span class=\"greek\">ἄρχω</span>), [in LXX for <span class=\"hebrew\">נשׂא</span>, <span class=\"hebrew\">רֹאשׁ</span>, <span class=\"hebrew\">שַׂר</span>, etc.;]"
