    "gloss": "strength",
    "vorm": "<b>βία</b>, <span class=\"greek\">-ας, ἡ</span>,",
    "definitie": "<em>strength</em>, <em>force</em>, <em>violence</em>: Ac 5:26 21:35 24:7 27:41.†",
