    "woord": "Γάδ",
    "gloss": "",
    "vorm": "<b>Γάδ</b>, <span class=\"greek\">ὁ</span>, indecl. (Heb. <span class=\"hebrew\">גָּד</span>),",
    "definitie": "Gad (Ge 30:11 49:13, al.): Re 7:5.†",
