    "gloss": "to grow old",
    "vorm": "<b>γηράσκω</b> (also <span class=\"greek\">γηράω</span>; < <span class=\"greek\">γῆρας</span>),",
    "definitie": "<em>to grow old</em>: Jo 21:18, He 8:13.†",
    "nt": "2",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">זקן</span>;]"
