  "G1445": {
    "woord": "Ἑβραῖος",
    "gloss": "a Hebrew",
    "vorm": "† <b>Ἑβραῖος</b> (WH, <span class=\"greek\">Ἐβ-</span>), <span class=\"greek\">-α, -ον</span> (Aram, <span class=\"hebrew\">עִבְרַי</span>), as subst., <span class=\"greek\">ὁ Ἑ.</span>,",
    "definitie": "<em>a Hebrew</em>. <br/>1. In OT, of Israelites in contrast with those of another race (Ge 14:13, Ex 1:15, De 15:12, al.). <br/>2. In NT as the correlative of <span class=\"greek\">Ἑλληνιστής</span>, a Jew who had adopted, in greater or less degree, Greek culture and Greek language. The distinction was not merely linguistic (<i>DB</i>, ii, 325); as far as it was so, <span class=\"greek\">Συριστής</span> would be a more correct Greek term for the Jew of Semitic speech (v.s. <span class=\"greek\">Ἑβραΐς</span>, and cf. Dalman, <i>Words</i>, 7): Ac 6:1, II Co 11:22, Phl 3:5.†",
    "nt": "4",
    "etymologie": "[in LXX for <span class=\"hebrew\">עֵבֶר</span>, <span class=\"hebrew\">עִבְרִי</span> ;]"
  },
  "G1446": {
    "woord": "Ἑβραΐς",
    "gloss": "Hebrew",
    "vorm": "**† <b>Ἑβραΐς</b> (WH, <span class=\"greek\">Ἐβ-</span>), <span class=\"greek\">-ίδος</span> (Aram. <span class=\"hebrew\">עִבְרַי</span>), peculiar form of <span class=\"greek\">Ἑβραϊκός</span>,",
    "definitie": "in NT, <span class=\"greek\">ἡ Ἑ. διάλεκτος</span>, <em>Hebrew</em>, i.e. the Aramaic vernacular of Palestine: Ac 21:40 22:2 26:14.†",
    "nt": "3",
    "etymologie": "[in LXX, <span class=\"greek\">ἡ Ἑ. φωνή</span>, IV Mac 12:7 16:15 * ;]"
  },
  "G1447": {
    "woord": "Ἑβραϊστί",
    "gloss": "in Hebrew",
    "vorm": "**† <b>Ἑβραϊστί</b> (WH, <span class=\"greek\">Ἐβ-</span>), adv.,",
    "definitie": "<em>in Hebrew</em>: Re 9:11; elsewhere, <em>in Aramaic</em> (v. supr.): Jo 5:2 19:13, 17, 20 20:16, Re 16:16.†",
    "nt": "7",
    "etymologie": "[in LXX: Si <i>prol.</i> 13 * ;]"
  },
  "G1448": {
    "woord": "ἐγγίζω",
    "gloss": "to bring near",
    "vorm": "<b>ἐγγίζω</b> (< <span class=\"greek\">ἐγγύς</span>).",
    "definitie": "<br/>1. trans., <em>to bring near</em>: Ge 48:10, Is 5:8. <br/>2. Intrans., <em>to come near</em>: absol., Mt 26:46, Mk 14:42, Lk 18:40 19:41 21:20, 28 24:15, Ac 21:33 23:15; c. adv., <span class=\"greek\">ὅπου</span>, Lk 12:33; c. dat., Lk 7:12 15:1, 25 22:47, Ac 9:3 10:9 22:6; <span class=\"greek\">τ. θεῷ</span>, He 7:19, Ja 4:8; seq. <span class=\"greek\">εἰς</span>, Mt 21:1, Mk 11:1, Lk 18:35 19:29 24:28; <span class=\"greek\">πρός</span>, c. dat., Lk 19:37; <span class=\"greek\">μέχρι θανάτου</span>, Phl 2:30; of time, <span class=\"greek\">ὥρα</span>, Mt 26:45; <span class=\"greek\">ἡμέρα</span>, Ro 13:12, He 10:25; <span class=\"greek\">καιρός</span>, Mt 21:34, Lk 21:8; <span class=\"greek\">χρόνος</span>, Ac 7:17; <span class=\"greek\">ἑορτή</span>, Lk 22:1; <span class=\"greek\">παρουσία</span>, Ja 5:8; <span class=\"greek\">τέλος</span>, I Pe 4:7; <span class=\"greek\">ἐρήμωσις</span>, Lk 21:20; <span class=\"greek\">ἀπολύτρωσις</span>, Lk 21:28; <span class=\"greek\">ἤγγικεν ἡ βασιλεία</span> (for similar expressions in Targ., v. Dalman, 106), Mt 3:2 4:17 10:7, Mk 1:15, Lk 10:9 (<span class=\"greek\">ἐφ’ ὑμᾶς</span>) 10:11 (cf. <span class=\"greek\">προσ-εγγίζω</span>), and v. Cremer, 224).†",
    "nt": "42",
    "etymologie": "[in LXX for <span class=\"hebrew\">נגשׁ</span>, <span class=\"hebrew\">קרב</span>, etc. ;]"
  },
