  "G1451": {
    "woord": "ἐγγύς",
    "gloss": "near",
    "vorm": "<b>ἐγγύς</b>, adv.,",
    "definitie": "<em>near</em>; <br/>1. of place: Jo 19:20, 42; as prep. c. gen. (M, <i>Pr.</i>, 99), Lk 19:11, Jo 3:23 6:19, 23 11:18, 54, Ac 1:12; c. dat., Ac 9:38 27:8; superl., <span class=\"greek\">ἔγγιστα</span>, Mk 6:36, WH, mg.; metaph., <span class=\"greek\">ֹοἱ ἐ.</span>, opp. to <span class=\"greek\">οἱ μακράν</span>, Eph 2:17; <span class=\"greek\">ἐ. γίνεσθαι</span>, Eph 2:13; <span class=\"greek\">ἐ. σου τὸ ῥῆμα</span>, Ro 10:8 <sup>(LXX)</sup>. <br/>2. Of time: Mt 24:32 26:18, Mk 13:28, 29, Lk 21:30, 31, Jo 2:13 6:4 7:2 11:55, Re 1:3 22:10; <span class=\"greek\">ὁ κύριος ἐ.</span>, Phl 4:5; seq. <span class=\"greek\">ἐπὶ θύραις</span>, Mt 24:33; compar., <span class=\"greek\">ἐγγύτερον</span> (neut. of adj. <span class=\"greek\">-ος</span>, used adverbially), Ro 13:11 (cf. R, txt.); as prep. c. gen., <span class=\"greek\">ἐ. κατάρας</span>, He 6:8; <span class=\"greek\">ἀφανισμοῦ</span>, He 8:13 (cf. Cremer, 223).†",
    "nt": "31",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">קָרֹוב</span> ;]"
  },
