  "G1482": {
    "woord": "ἐθνικός",
    "gloss": "national",
    "vorm": "**† <b>ἐθνικός</b>, <span class=\"greek\">-ή, -όν</span>, (< <span class=\"greek\">ἔθνος</span>), [in Al.: Le 21:7 * ;]",
    "definitie": "<br/>1. <em>national</em> (Polyb.). <br/>2. <em>foreign</em> (gramm.); in NT, as subst., <span class=\"greek\">ὁ ἐ.</span>, <em>the Gentile</em> (the adj. \"describes character rather than mere position\"; cf. <span class=\"greek\">ἔθνος</span>, and v. Cremer, 228): Mt 5:47 6:7 18:17, III Jo 7.†",
    "nt": "5"
  },
