  "G1497": {
    "woord": "εἴδωλον",
    "gloss": "a phantom, image, likeness",
    "vorm": "<b>εἴδωλον</b>, <span class=\"greek\">-ου, τό</span>",
    "definitie": "<br/>1. in cl. <br/>(a) <em>a phantom, image, likeness</em>; <br/>(b) <em>an image in the mind, an idea, fancy</em>. <br/>2. In LXX and NT, <br/>(a) <em>an image of a god, an idol</em> (cf. Polyb., xxxi, 3, 13): Ac 7:41, I Co 12:2, Re 9:20; <br/>(b) <em>the false god</em> or <em>idol worshipped in an image</em> (<i>ICC</i>, on I Th, l.c.): Ac 15:20, Ro 2:22, I Co 8:4, 7 10:19 II Co 6:18, I Th 1:9, I Jo 5:21.†",
    "nt": "11",
    "etymologie": "(< <span class=\"greek\">εἶδος</span>), [in LXX for <span class=\"hebrew\">אֱלֹוהָּ</span>, <span class=\"hebrew\">גְּלוּלִים</span>, etc. ;]"
  },
  "G1500": {
    "woord": "εἰκῇ",
    "gloss": "without cause",
    "vorm": "<b>εἰκῇ</b> (<span class=\"greek\">-ῆ</span>, Rec., as in cl.), adv.,",
    "definitie": "<br/>1. <em>without cause</em> or <em>reason</em>: Mt 5:22 (E, mg.), Col 2:18 (<i>ICC</i>). <br/>2. <em>vainly, fruitlessly, to no purpose</em>: Ro 13:4, I Co 15:2, Ga 3:4 4:11, Col 2:18.†",
    "nt": "6",
    "etymologie": "[in LXX: Pr 28:25 (<span class=\"greek\">εἰκῇ</span>)* ;]"
  },
