    "vorm": "<b>θερμαίνω</b>",
    "definitie": "<em>to warm</em>, <em>heat</em>; mid., <em>to warm oneself</em>: Mk 14:54, 67, Jo 18:18, 25, Ja 2:16.†",
    "nt": "6",
    "etymologie": "(< <span class=\"greek\">θερμός</span>), [in LXX chiefly for <span class=\"hebrew\">חמם</span>;]"
