    "gloss": "Jairus",
    "vorm": "<b>Ἰάειρος</b>, <span class=\"greek\">-ου, ὁ</span> (Heb. <span class=\"hebrew\">יָאִיר</span>, Nu 32:41),",
    "definitie": "<em>Jairus</em>: Mk 5:22, Lk 8:41.†",
