  "G2414": {
    "woord": "Ἱεροσόλυμα",
    "gloss": "Jerusalem",
    "vorm": "<b>Ἱεροσόλυμα</b> (WH, <span class=\"greek\">Ἰερ-</span>, v. <i>Intr.</i>, § 408), <span class=\"greek\">-ων, τά</span> (on <span class=\"greek\">πᾶσα Ἱ.</span>, Mt 2:3, v. WM, 794; M, <i>Pr.</i>, 48, 244; Thayer, s.v.), and <span class=\"greek\">Ἱερουσαλήμ</span> (WH, <span class=\"greek\">Ἰερ-</span>), <span class=\"greek\">ἡ.</span>, indecl., as always in LXX exc. some parts of Apocr. (Heb. <span class=\"hebrew\">יְרוּשָׁלַיִם</span>, <span class=\"hebrew\">יְרוּשָׁלֵם</span>), the former always in FlJ, Mk, Jo <sup>ev.</sup> and Mt (exc. Mt 27:37), and most freq. in Lk, the latter always in He, Re, and by St. Paul (exc. Ga 1:17, 18 2:1),",
    "definitie": "<em>Jerusalem</em>: Mt 2:1, Mk 3:8, Jo 1:19, al.; its inhabitants, Mt 2:3 3:5 23:37, Lk 13:34. Symbolically, <span class=\"greek\">ἡ- ἄνω Ἱ.</span>, Ga 4:26, contrasted with <span class=\"greek\">ἡ νῦν Ἱ.</span>, Ga 4:25; <span class=\"greek\">Ἱ. ἐπουράνιος</span>, He 12:22; <span class=\"greek\">ἡ καινὴ Ἱ.</span>, Re 3:12 21:2, 10.",
    "nt": "62"
  },
