    "gloss": "sufficiency",
    "vorm": "* <b>ἱκανότης</b>, <span class=\"greek\">-ητος, ἡ</span>",
    "definitie": "<em>sufficiency</em>, <em>ability</em> (Plat.): II Co 3:5.†",
    "nt": "1",
    "etymologie": "(< <span class=\"greek\">ἱκανός</span>),"
