    "vorm": "† <b>ἱκανόω</b>, <span class=\"greek\">-ῶ</span>",
    "definitie": "<em>to make sufficient</em>, <em>render fit</em>: c. dupl. acc., II Co 3:6; c. acc. pers. seq. <span class=\"greek\">εἰς</span>, Col 1:12.†",
