  "G2453": {
    "woord": "Ἰουδαῖος",
    "gloss": "Jewish",
    "vorm": "<b>Ἰουδαῖος</b>, <span class=\"greek\">-αία, -αῖον</span>",
    "definitie": "<em>Jewish</em>: <span class=\"greek\">ἀνήρ</span>, Ac 10:28 22:3; <span class=\"greek\">ἄνθρωπος</span>, Ac 21:39; <span class=\"greek\">ψευδοπροφήτης</span>, 13:6; <span class=\"greek\">ἀσχιερεύς</span>, 19:14; <span class=\"greek\">γυνή</span>, 16:1 24:24; <span class=\"greek\">γῆ</span>, Jo 3:22; <span class=\"greek\">χώρα</span>, Mk 1:5. Substantively, <br/>(a) <span class=\"greek\">Ἰουδαῖος, ὁ</span>, <em>a Jew</em>: Jo 4:9, Ac 18:24, Ro 2:28; pl., Re 2:9 3:9; <span class=\"greek\">οἱ Ἰ.</span>, Mt 2:2, Mk 7:3, Jo 2:6, al.; <span class=\"greek\">Ἰ. τε καὶ Ἕλληνες</span>, Ac 14:1, al.; <span class=\"greek\">κ. προσήλυτοι</span>, Ac 2:10; <span class=\"greek\">ἔθνη τε κ. Ἰ.</span>, Ac 14:5; <span class=\"greek\">οἱ κατὰ τὰ ἔθνη Ἰ.</span>, Ac 21:21; of Jewish Christians, Ga 2:13; of the ruling class who opposed Jesus, Jo 1:19 2:18 5:10 11:8 13:33, al.; <br/>(b) <span class=\"greek\">Ἰουδαία, -ας, ἡ</span> (sc. <span class=\"greek\">γῆ, χώρα</span>, cf. Jo 3:22, Mk 1:5), (Heb. <span class=\"hebrew\">יְהוּדָה</span>), <em>Judæa</em>: Mt 2:1, Lk 1:5, Jo 4:3, al.",
    "nt": "193",
    "etymologie": "(< <span class=\"greek\">Ἰούδας</span>),"
  },
