    "woord": "Ἰούδας",
    "gloss": "Judah",
    "vorm": "<b>Ἰούδας</b>, <span class=\"greek\">-α</span>, dat. <span class=\"greek\">-ᾳ</span>, acc. <span class=\"greek\">-αν</span>",
    "definitie": "<em>Judah</em>, son of Jacob: Mt 1:2, 3, Lk 3:33; <span class=\"greek\">φυλή Ἰ.</span>, Re 5:5 7:5; by meton., of the tribe, He 7:14; of its confines, <span class=\"greek\">γῆ Ἰ.</span>, Mt 2:6;<span class=\"greek\">πόλις Ἰ.</span>, Lk 1:39.",
