    "vorm": "<b>ἰσχύω</b>",
    "definitie": "<em>to be strong</em> in body: Mt 9:12, Mk 2:17.",
    "nt": "28",
    "etymologie": "(< <span class=\"greek\">ἰσχύς</span>), [in LXX for <span class=\"hebrew\">חזק</span>, <span class=\"hebrew\">גִּבּוֹר</span>, <span class=\"hebrew\">עצם</span>, etc.;]"
