  "G2500": {
    "woord": "Ἰωσῆς",
    "gloss": "Joses",
    "vorm": "<b>Ἰωσῆς</b>, <span class=\"greek\">-ῆ</span> (Rec. <span class=\"greek\">-ή</span>, Lk 3:29; AV, <i>Jose</i>; v.s. <span class=\"greek\">Ἰησοῦς</span>, 3), and <span class=\"greek\">-ῆτος</span> (Mk 6:3 15:40, 47), <span class=\"greek\">ὁ</span>,",
    "definitie": "<em>Joses</em>; <br/>1. brother of our Lord: Mk 6:3, Mt 13:55 (Rec., v.s. <span class=\"greek\">Ἰωσήφ</span>). <br/>2. Son of Mary: Mt 27:56 (<span class=\"greek\">-σήφ</span>, WH, txt), Mk 15:40, 47. <br/>3. v.s. <span class=\"greek\">Βαρνάβας</span>.†",
    "nt": "3"
  },
  "G2501": {
    "woord": "Ἰωσήφ",
    "gloss": "Joseph",
    "vorm": "<b>Ἰωσήφ</b>, indecl.",
    "definitie": "<em>Joseph</em>; <br/>1. the Son of Jacob: Jo 4:5, Ac 7:9, 13, 14, 18, He 11:21, 22, Re 7:8. <br/>2. In the genealogy of our Lord, <br/>(a) the son of Matthias: Lk 3:24; <br/>(b) the son Joram: Lk 3:30. <br/>3. The husband of Mary, the Lord's mother: Mt 1:16 ff., Lk 1:27, Jo 1:46, al. <br/>4. One of the brethren of our Lord (v.s. <span class=\"greek\">ἀδελφός</span>): Mt 13:55. <br/>5. Son of Mary: Mt 27:56 (<span class=\"greek\">-σῆς</span>, WH, mg., RV). <br/>6. <em>Joseph</em> of Arimatbæa: Mt 27:57, 59, Mk 15:43, 45, Lk 23:50, Jo 19:38. <br/>7. v.s. <span class=\"greek\">Βαρνάβας</span>. <br/>8. v.s. <span class=\"greek\">Βαρσαβᾶς</span>.",
    "nt": "35",
    "etymologie": "(FlJ, <span class=\"greek\">Ἰώσηπος, -ου</span>), <span class=\"greek\">ὁ</span> (Heb. <span class=\"hebrew\">יוֹסֵף</span>),"
  },
