    "vorm": "<b>κατα-γινώσκω</b>",
    "definitie": "<em>to blame</em>, <em>condemn</em>: c. gen. pers., I Jo 3:20, 21; pass., <span class=\"greek\">κατεγνωσμένος ἦν</span> (RV, <i>he stood condemned</i>, v. Ellie., in l.; but cf. Field, <i>Notes</i>, 188): Ga 2:11.†",
    "nt": "3",
