    "nt": "27",
    "etymologie": "(< <span class=\"greek\">κατά</span>, causative, <span class=\"greek\">ἀργός</span> = <span class=\"greek\">ἀ-εργός</span>), [in LXX: II Es 4.21, 23 5.5 6.8 (<span class=\"hebrew\">בְּטֵל</span>)*;]"
