    "vorm": "<b>κλείω</b>,",
    "definitie": "<em>to shut</em>: <span class=\"greek\">θύραν</span>, Mt 6:6; <span class=\"greek\">τ. ἄβυσσον</span>, Re 20:3; pass., <span class=\"greek\">θύρα</span>, Mt 25:10, Lk 11:7 (pl.), Jo 20:19, 26, Ac 21:30; <span class=\"greek\">δεσμωτήριον</span>, Ac 5:23; <span class=\"greek\">πυλῶνες</span>, Re 21:25. Metaph., <span class=\"greek\">τ. οὐρανόν</span>, Lk 4:25, Ro 11:6; <span class=\"greek\">τ. σπλάγχνα</span>, I Jo 3:17; <span class=\"greek\">τ. βασιλείαν</span>, Mt 23:14; id. absol., Re 3:7; <span class=\"greek\">τ. θύραν</span>, Re 3:8. (Cf. <span class=\"greek\">ἀπο-</span>, <span class=\"greek\">ἐκ-</span>, <span class=\"greek\">κατα-</span>, <span class=\"greek\">συν-κλείω</span>.)†",
    "nt": "16",
