    "gloss": "Lydda",
    "vorm": "<b>λύδδα</b>, <span class=\"greek\">-ας</span> (Ac 9:38, <span class=\"greek\">-ης</span> Rec.), <span class=\"greek\">ἡ</span> and <span class=\"greek\">λύδδα, -ων, τά</span> (Ac 9:32, 35; <span class=\"greek\">-αν</span>, Rec.), (Heb. <span class=\"hebrew\">לֹד</span>),",
    "definitie": "<em>Lydda</em> (modern <i>Ludd</i>): Ac 9:32, 35, 38.†",
    "nt": "3"
