    "vorm": "<b>λυτρόω</b>, <span class=\"greek\">-ῶ</span>",
    "definitie": "<em>to release on receipt of ransom</em>; mid., <em>to release by paying ransom</em>, <em>to redeem</em>: in spiritual sense, Tit 2:14; pass, I Pe 1:18; in general sense, <em>to deliver</em> (cf. Ex 6:6, Ps 68 (69):18, al.): Lk 24:21.†",
    "nt": "3",
