  "G3441": {
    "woord": "μόνος",
    "gloss": "alone",
    "vorm": "<b>μόνος</b>, <span class=\"greek\">-η, -ον</span>,",
    "definitie": "<br/>1. adj., <em>alone</em>, <em>solitary</em>, <em>forsaken</em>: c. verb., Mt 14:23, Mk 6:47, Lk 9:36, al.; c. pron., Mt 18:15, Mk 9:2, al.; c. subst., Mk 9:8, Lk 4:8, al.; pleonast., <span class=\"greek\">οὐκ . . . εἰ μὴ μ.</span>, Mt 12:4, Lk 6:4, al.; attrib., <em>only</em>, (<span class=\"greek\">ὁ</span>) <span class=\"greek\">μ. θεός</span>, Jo 5:44 17:3, Ro 16:27, I Ti 1:17, Ju 25. <br/>2. As adv., <br/>(a) neut., <span class=\"greek\">μόνον</span>, <em>alone</em>, <em>only</em>: referring to verb or predic., Mt 9:21, Mk 5:36, Ja 1:22, al. (v. Bl., §44, 2); <span class=\"greek\">οὐ</span> (<span class=\"greek\">μὴ</span>) <span class=\"greek\">μ.</span>, Ga 4:18, Ja 1:22; <span class=\"greek\">οὐ μ. . . . ἀλλά</span> (Bl., § 77, 133), Ac 19:26, I Jo 5:6, al.; id. seq. <span class=\"greek\">καί</span> (Bl., § 81, 12), Ro 5:3 9:10, II Co 8:19, al.; <br/>(b) <span class=\"greek\">κατὰ μόνας</span>, <em>alone</em> (Bl., § 44, 1), Mk 4:10, Lk 9:18.",
    "nt": "112",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">לְבַד</span>;]"
  },
