    "definitie": "<em>that which is established by usage</em>, <em>a custom</em>.",
    "nt": "1",
    "etymologie": "(< <span class=\"greek\">νομίζω</span>), [in LXX: Es 8:36 (<span class=\"hebrew\">דָּת</span>), Ne 7:71 R (<span class=\"hebrew\">דַּרְכְּמוֹן</span>), I Mac 15:6*;]"
