    "definitie": "<em>a putting around</em>, <em>putting on</em>: I Pe 3:3.†",
    "nt": "1",
    "etymologie": "(< <span class=\"greek\">περιτίθημι</span>), [in Sm.: Ps 31 (32):9*;]"
