    "nt": "4",
    "etymologie": "(or <span class=\"greek\">πρᾶος</span>, v. Bl., § 3, 3), <span class=\"greek\">-α</span>, <span class=\"greek\">-ον</span> (v. LS, Thayer, s.v.), [in LXX (always <span class=\"greek\">-ΰς</span>, exc. II Mac 15:12, <span class=\"greek\">-ᾷος</span>, v. Thackeray, <i>Gr.</i>, 180 f.) for <span class=\"hebrew\">עָנָו</span>, <span class=\"hebrew\">עָנָיו</span>, <span class=\"hebrew\">עָנִי</span>;]"
