    "gloss": "an aged woman",
    "vorm": "** <b>πρεσβῦτις</b>, <span class=\"greek\">-ιδος, ἡ</span>, fem, of <span class=\"greek\">πρεσβύτης</span>,",
    "definitie": "<em>an aged woman</em>: Tit 2:3.†",
