    "vorm": "<b>πυλών</b>, <span class=\"greek\">-ῶνος, ὁ</span>",
    "definitie": "the <em>porch</em> or <em>vestibule</em> of a house or palace: Mt 26:71, Lk 16:20, Ac 10:17 12:13, 14.",
    "nt": "18",
