    "vorm": "<b>Σαῦλος</b>, <span class=\"greek\">-ου, ὁ</span> (Hellenized form of <span class=\"greek\">Σαούλ</span>, q.v.),",
    "definitie": "<em>Saul</em>, the Jewish name of the Apostle Paul: Ac 7:58 8:1, 3 9:1, 8, 11, 22, 24 11:25, 30 12:25 13:1, 2, 7, 9.†",
    "nt": "15"
