  "G4572": {
    "woord": "σεαυτοῦ",
    "gloss": "of, to",
    "vorm": "<b>σεαυτοῦ</b>, <span class=\"greek\">-ῆς, -οῦ</span>",
    "definitie": "(<em>of, to</em>) <em>thyself</em>: Mt 4:6, Jo 8:13, I Ti 4:16, al. (In Hellenistic, the pl. is <span class=\"greek\">ἑαυτῶν</span> (q.v.), not <span class=\"greek\">ὑμῶν αὐτῶν</span> as in Attic, v. Bl., § 13, 1.) †",
    "nt": "43",
    "etymologie": "(in NT not contracted, <span class=\"greek\">σαυτοῦ</span>, as in Att..),"
  },
