  "G4632": {
    "woord": "σκεῦος",
    "gloss": "a vessel, implement",
    "vorm": "<b>σκεῦος</b>, <span class=\"greek\">-ους, τό </span>",
    "definitie": "<em>a vessel, implement</em> (for exx. in various senses, v. MM, xxii): Mk 11:16, Lk 8:16, Jo 19:29, Ac 10:11, 16 11:5, Ro 9:21, Re 18:12; pl., II Ti 2:20, Re 2:27; <span class=\"greek\">τὰ σ. τῆς λειτουργίας</span>, He 9:21; pl., <span class=\"greek\">τὰ σ.</span>, <em>utensils, goods</em>, Mt 12:29, Mk 3:27, Lk 17:31; id. of the <em>tackle</em> or <em>gear</em> of a ship (Xen., Polyb., al.); so in sing., <span class=\"greek\">τὸ σ.</span>, Ac 27:17. Metaph., of persons: <span class=\"greek\">σ. ἐκλογῆς</span>, Ac 9:15; <span class=\"greek\">ὀργῆς</span>, Ro 9:22; <span class=\"greek\">ἐλέους</span>, ib. 23; <span class=\"greek\">σ. εἰς τιμήν</span> (cf. Ro 9:21), II Ti 2:21; of woman, <span class=\"greek\">ἀσθενέστερον σ.</span>, I Pe 3:7; so perh. <span class=\"greek\">τ. ἑαυτοῦ σ.</span>, I Th 4:4 (but v. infr.); of the body, II Co 4:7; so perh. I Th 4:4 (but v. supr., and v.s. <span class=\"greek\">κτάομαι</span>).†",
    "nt": "23",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">כְּלִי</span> ;]"
  },
  "G4633": {
    "woord": "σκηνή",
    "gloss": "a tent, booth, tabernacle",
    "vorm": "<b>σκηνή</b>, <span class=\"greek\">-ῆς, ἡ </span>",
    "definitie": "<em>a tent, booth, tabernacle</em>: Mt 17:4, Mk 9:5, Lk 9:33, He 11:9; <span class=\"greek\">αἱ αἰώνιοι σ.</span>, Lk 16:9; of the Mosaic tabernacle, He 8:5 9:2, 3, 6, 8, 21; <span class=\"greek\">σ. τ. μαρτυρίου</span>, Ac 7:44; of its heavenly prototype, He 8:2 9:11, Re 13:6 15:5 21:3; of the temple, He 13:10; <span class=\"greek\">ἡ σ. τοῦ Μολόχ</span>, Ac 7:43 <sup>(LXX)</sup>; metaph., <span class=\"greek\">ἡ σ. Δαυείδ</span> Ac 15:16 <sup>(LXX)</sup>.†",
    "nt": "20",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">אֹהֶל</span>, also for <span class=\"hebrew\">מִשְׁכָּן</span>, <span class=\"hebrew\">סֻכָּה</span>, etc. ;]"
  },
