  "G5111": {
    "woord": "τολμάω",
    "gloss": "to have courage, to venture, dare, be bold",
    "vorm": "<b>τολμάω</b>, <span class=\"greek\">-ῶ </span>",
    "definitie": "<em>to have courage, to venture, dare, be bold</em>: absol, II Co 11:21; seq. <span class=\"greek\">ἐπί</span>, II Co 10:2; c. inf. (Bl., § 69, 4), Mt 22:46, Mk 12:34, Lk 20:40, Jo 21:12, Ac 5:13 7:32, Ro 15:18, I Co 6:1, II Co 10:12, Phl 1:14, Ju 9; <em>to submit to</em> (in cl. usually absol. in this sense), Ro 5:7 (v. Field, <i>Notes</i>, 155); <span class=\"greek\">τολμήσας εἰσῆλθεν</span>, <em>took courage and went in</em> (v. Field, <i>op. cit.</i>, 44), Mk 15:43 (cf. <span class=\"greek\">ἀπο-τολμάω</span>).†",
    "nt": "16",
    "etymologie": "[in LXX: Jb 15:12 (<span class=\"hebrew\">לָקַח</span>), Es 1:18 7:5 (<span class=\"hebrew\">לֵב</span> <span class=\"hebrew\">מָלֵא</span>) Jth 14:13, II Mac 4:2, III Mac 3:21 R, IV Mac 8:18 * ;]"
  },
