  "G5154": {
    "woord": "τρίτος",
    "gloss": "the third",
    "vorm": "<b>τρίτος</b>, <span class=\"greek\">-η, -ον </span>",
    "definitie": "<em>the third</em>: Mt 22:26, Mk 12:21 15:25, Lk 24:21, Ac 2:15, al.; <span class=\"greek\">τῇ τ. ἡμέρᾳ</span> (i.e. <em>the next day but one</em>: Xen., al.; v. Field, <i>Notes</i>, 11 ff.), Mt 16:21, Lk 24:46, al.; substantively, acc. masc., <span class=\"greek\">τρίτον</span>, <em>a third</em> (servant), Lk 20:12; neut., <span class=\"greek\">τὸ τ.</span>, c. gen., <em>the third part of</em>: Re 8:7-12 9:15, 18 12:4. As adv., <span class=\"greek\">τὸ τ.</span>, <em>the third time</em>: Mk 14:41, Jo 21:17; anarth., <span class=\"greek\">τρίτον</span>, a third time, Lk 23:22, Jo 21:14, II Co 12:14 13:1; in enumerations, <em>thirdly</em>, I Co 12:28; <span class=\"greek\">ἐκ τ.</span>, <em>a third time</em>, Mt 26:44",
    "nt": "55"
  },
