  "G5259": {
    "woord": "ὑπό",
    "gloss": "under",
    "vorm": "<b>ὑπό</b> (before smooth breathing <span class=\"greek\">ὑπ’</span>, Mt 8:9<sup>b</sup>, Lk 7:8<sup>b</sup>; before rough breathing <span class=\"greek\">ὑφ’</span>, Ro 3:9; on the neglect of elision in Mt, Lk, ll. c.<sup>a</sup>, Ga 3:22, v. WH, <i>App.</i>, 146; Tdf., <i>Pr.</i>, iv),",
    "definitie": "<br/>I. C. gen., primarily of place, <em>under</em>, hence, metaph., of the efficient cause, <em>by</em>: after passive verbs, c. gen. pers., Mt 1:22, Mk 1:5, Lk 2:18, Jo 14:21, Ac 4:11, I Co 1:11, He 3:4, al.; c. gen. rei, Mt 8:24, Lk 7:24, Ro 3:21, al.; with neut. verbs and verbs with pass. meaning, Mt 17:12, Mk 5:26, I Co 10:9, 10 I Th 2:14, al. <br/>II. C. acc., <em>under</em>; <br/>1. of motion: Mt 5:15 8:8, Mk 4:21, Lk 13:34; hence, metaph., of subjection, Ro 7:14, I Co 15:27, Ga 3:22, I Pe 5:6, al. <br/>2. Of position: Jo 1:49, Ac 4:12, Ro 3:13, I Co 10:1, al.; hence, metaph., <em>under, subject to</em>, Mt 8:9, Ro 3:9, I Co 9:20, Ga 4:5, al. <br/>3. Of time, <em>about</em>: Ac 5:21. <br/>III. In composition: <em>under</em> (<span class=\"greek\">ὑποδέω</span>), hence, of <em>subjection</em> (<span class=\"greek\">ὑποτάσσω</span>), compliance (<span class=\"greek\">ὑπακούω</span>), <em>secrecy</em> (<span class=\"greek\">ὑποβάλλω</span>), <em>diminution</em> (<span class=\"greek\">ὑποπνέω</span>).",
    "nt": "211"
  },
