  "G5343": {
    "woord": "φεύγω",
    "gloss": "to flee from",
    "vorm": "<b>φεύγω </b>",
    "definitie": "<em>to flee from</em> or <em>away, take flight</em>: absol., Mt 8:33 26:56, Mk 5:14 14:50, Lk 8:34, Jo 10:12, Ac 7:29; seq. <span class=\"greek\">εἰς</span>, Mt 2:13 10:23 24:16 (WH, txt.), Mk 13:14, Lk 21:21, Re 12:6; <span class=\"greek\">ἐπί</span>, c. acc. loc., Mt 24:16 (WH, mg.); <span class=\"greek\">ἐκ</span>, Ac 27:30; <span class=\"greek\">ἀπό</span>, c. gen. loc. (cl.), Mk 16:8; id. c. gen. pers. (as in Heb.), Jo 10:5, Ja 4:7. Metaph.: absol., Re 16:20; c. acc. rei, I Co 6:18, He 11:34 (v. M, <i>Pr.</i>, 116); opp. to <span class=\"greek\">διώκειν</span>, I Ti 6:11, II Ti 2:22; seq. <span class=\"greek\">ἀπό</span>, c. gen. pers., Re 9:6; <span class=\"greek\">ἀπὸ τ. προσώπου</span>, Re 20:11; c. gen. rei, Mt 3:7 (M, <i>Pr.</i>, l.c.) 23:33, Lk 3:7, I Co 10:14 (cf. <span class=\"greek\">ἀπο-</span>, <span class=\"greek\">δια-</span>, <span class=\"greek\">ἐκ-</span>, <span class=\"greek\">κατα-φεύγω</span>).†",
    "nt": "29",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">נוּס</span>, also for <span class=\"hebrew\">בּרח</span>, etc. ;]"
  },
