  "G5495": {
    "woord": "χείρ",
    "gloss": "the hand",
    "vorm": "<b>χείρ</b>, gen., <span class=\"greek\">χειρος</span> (acc., <span class=\"greek\">χεῖραν</span>, I Pe 5:6 T), <span class=\"greek\">ἡ</span>,",
    "definitie": "<em>the hand</em>: Mt 3:12, Mk 3:1, Lk 6:6, al. mult.; <span class=\"greek\">ἡ χ.</span>, acting subject, Lk 22:21; pl., Ac 17:25 20:34, I Jo 1:1; <span class=\"greek\">τ. ἔργα τῶν χ.</span>, Ac 7:41, Re 9:20; <span class=\"greek\">ὁ ἀσπασμὸς τ. ἐμῇ χ.</span>, I Co 16:21, Col 4:18, II Th 3:17; prepositional phrases, esp. those without art., similar to Heb. constructions (Bl., §32, 4; 40, 9; 46, 9), <span class=\"greek\">ἐν χ.</span>; c gen. (Lft., in l.), Ga 3:19; <span class=\"greek\">σὺν χ. ἀγγέλου</span>, Ac 7:35; <span class=\"greek\">διὰ (τῶν) χειρῶν (διὰ χειρός)</span>, Mk 6:2, Ac 5:12 7:25, al.; <span class=\"greek\">ἐπὶ χειρῶν</span>, Mt 4:6, Lk 4:11; ellipse of <span class=\"greek\">χ.</span> (<span class=\"greek\">ἡ δεξία, ἀριστερα</span>; Bl., § 44, 1), Mt 6:3, al. By meton., for the power or activity of an individual, Mt 17:22, Mk 9:31, Lk 9:44, Jo 10:39, Ac 12:11, al.; metaph., of the activity or power of God: Lk 1:66 23:46, Jo 10:29, Ac 11:21 13:11, al.",
    "nt": "177",
    "etymologie": "[in LXX chiefly for <span class=\"hebrew\">יָד</span> ;]"
  },
