    "definitie": "<em>to lead by the hand</em>: Ac 9:8 22:11.†",
    "nt": "2",
    "etymologie": "(< <span class=\"greek\">χειραγωγός</span>), [in LXX: Jg 16:26 A (<span class=\"hebrew\">בְּיָר</span> <span class=\"hebrew\">מַחֲזׅיק</span>), To 11:16 <span class=\"hebrew\">א</span> * ;]"
